}


@dataclass(frozen=True)
class FieldSpec:
    name: str
    minimum: int
    maximum: int


@dataclass(frozen=True)
class CronField:
    spec: FieldSpec
    expression: str
    values: tuple[int, ...]

    @property
    def is_wildcard(self) -> bool:
        return len(self.values) == self.spec.maximum - self.spec.minimum + 1


@dataclass(frozen=True)
class CronSchedule:
    minute: CronField
    hour: CronField
    day_of_month: CronField
    month: CronField
    day_of_week: CronField

    def describe(self) -> str:
        if self._is_every_minute():
            return "Every minute"

