        )

        if time_description and date_parts:
            return f"{time_description} {date_parts}"

        if time_description:
            return time_description

        if date_parts:
            return f"Every minute {date_parts}"

        return "Every minute"

    def _is_every_minute(self) -> bool:
        return (
            self.minute.is_wildcard
            and self.hour.is_wildcard
            and self.day_of_month.is_wildcard
            and self.month.is_wildcard
            and self.day_of_week.is_wildcard
        )


FIELD_SPECS = (
    FieldSpec("minute", 0, 59),
    FieldSpec("hour", 0, 23),
    FieldSpec("day_of_month", 1, 31),
    FieldSpec("month", 1, 12),
    FieldSpec("day_of_week", 0, 6),
)


def parse_cron(expression: str) -> CronSchedule:
    parts = expression.split()

    if len(parts) != 5:
        raise ValueError(
            f"Expected 5 cron fields, got {len(parts)}: {expression!r}"
        )

    fields = [
        parse_field(part, spec)
        for part, spec in zip(parts, FIELD_SPECS)
    ]

    return CronSchedule(
        minute=fields[0],
        hour=fields[1],
        day_of_month=fields[2],
        month=fields[3],
        day_of_week=fields[4],
    )


def parse_field(expression: str, spec: FieldSpec) -> CronField:
    if not expression:
        raise ValueError(f"{spec.name} field cannot be empty")

    values: set[int] = set()

    for item in expression.split(","):
        if not item:
            raise ValueError(f"Empty list item in {spec.name} field: {expression!r}")

        values.update(parse_field_item(item, spec))

    return CronField(
        spec=spec,
        expression=expression,
        values=tuple(sorted(values)),
    )


def parse_field_item(item: str, spec: FieldSpec) -> set[int]:
    base, step = split_step(item, spec)

    if base == "*":
        start = spec.minimum
        end = spec.maximum
    elif "-" in base:
        start, end = parse_range(base, spec)
    else:
        start = end = parse_number(base, spec)

    if step <= 0:
        raise ValueError(f"Step must be positive in {spec.name} field: {item!r}")

    return set(range(start, end + 1, step))


def split_step(item: str, spec: FieldSpec) -> tuple[str, int]:
    if "/" not in item:
        return item, 1

    parts = item.split("/")

    if len(parts) != 2 or not parts[0] or not parts[1]:
        raise ValueError(f"Invalid step syntax in {spec.name} field: {item!r}")

    return parts[0], parse_positive_integer(parts[1], spec, item)


def parse_range(text: str, spec: FieldSpec) -> tuple[int, int]:
    parts = text.split("-")

    if len(parts) != 2 or not parts[0] or not parts[1]:
        raise ValueError(f"Invalid range syntax in {spec.name} field: {text!r}")

    start = parse_number(parts[0], spec)
    end = parse_number(parts[1], spec)

    if start > end:
        raise ValueError(
            f"Invalid range in {spec.name} field: start {start} is greater than end {end}"
        )

    return start, end


def parse_number(text: str, spec: FieldSpec) -> int:
    value = parse_positive_integer(text, spec, text)

    if value < spec.minimum or value > spec.maximum:
        raise ValueError(
            f"{spec.name} value {value} is outside allowed range "
            f"{spec.minimum}-{spec.maximum}"
        )

    return value


def parse_positive_integer(text: str, spec: FieldSpec, original: str) -> int:
    if not text.isdigit():
        raise ValueError(f"Invalid number in {spec.name} field: {original!r}")

    return int(text)


def describe_time(minute: CronField, hour: CronField) -> str:
    if minute.is_wildcard and hour.is_wildcard:
