def describe_date_parts(
    day_of_month: CronField,
    month: CronField,
    day_of_week: CronField,
) -> str:
    parts: list[str] = []

    if not day_of_month.is_wildcard:
        parts.append(f"on the {describe_ordinals(day_of_month.values)}")

    if not month.is_wildcard:
        parts.append(f"in {describe_named_values(month.values, MONTH_NAMES)}")

    if not day_of_week.is_wildcard:
        parts.append(f"on {describe_days(day_of_week)}")

    if not parts:
        return ""

    if day_of_month.values == (1,) and month.is_wildcard and day_of_week.is_wildcard:
        return "on the 1st of every month"

    return " ".join(parts)


def describe_days(day_of_week: CronField) -> str:
    if "-" in day_of_week.expression and "," not in day_of_week.expression:
        start, end = parse_range(day_of_week.expression.split("/")[0], day_of_week.spec)
        return f"{DAY_NAMES[start]} through {DAY_NAMES[end]}"

    return describe_named_values(day_of_week.values, DAY_NAMES)


def describe_named_values(values: Iterable[int], names: dict[int, str]) -> str:
    return join_english([names[value] for value in values])


def describe_values(values: Iterable[int]) -> str:
    return join_english([str(value) for value in values])


def describe_ordinals(values: Iterable[int]) -> str:
    return join_english([ordinal(value) for value in values])


def join_english(items: list[str]) -> str:
    if not items:
        return ""

    if len(items) == 1:
        return items[0]

    if len(items) == 2:
        return f"{items[0]} and {items[1]}"

    return f"{', '.join(items[:-1])}, and {items[-1]}"


def format_time(hour: int, minute: int) -> str:
    if hour == 0 and minute == 0:
        return "midnight"

    return f"{hour:02d}:{minute:02d}"


def ordinal(value: int) -> str:
    if 10 <= value % 100 <= 20:
        suffix = "th"
    else:
        suffix = {
            1: "st",
            2: "nd",
            3: "rd",
        }.get(value % 10, "th")

    return f"{value}{suffix}"


def is_simple_step(expression: str, prefix: str) -> bool:
    return expression.startswith(prefix) and expression[len(prefix):].isdigit()


